INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'rapid_fire', 'easy', E'Which of the following describes the ''Perceive'' step in the expanded Agent Loop (Perceive → Ground → Reason → Act...)?\nA) The agent makes a recommendation.\nB) The agent updates its institutional memory.\nC) The agent receives a task, query, or trigger alongside the current enterprise state.\nD) The agent decides to shut down.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'rapid_fire', 'easy', E'What is the purpose of ''Text Chunking'' in an Agentic RAG system?\nA) To ensure the entire original document is always used.\nB) To break down content into smaller, manageable pieces for efficient processing and embedding.\nC) To delete unnecessary data from the system.\nD) To increase API costs.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'rapid_fire', 'easy', E'When an AI agent is performing ''institutional reasoning'' within an enterprise, what is it drawing upon in addition to generic LLM inference?\nA) Random Wikipedia articles.\nB) Accumulated knowledge and judgment encoded in enterprise context (e.g., policies, precedents).\nC) Today''s weather forecast.\nD) The current price of Bitcoin.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'What is the primary purpose of the ''Reflection'' or ''Self-Correction'' step in an advanced Agentic AI loop?\nA) To check for grammatical errors in the output.\nB) To review past actions and outcomes against the original goal, enabling course correction and learning.\nC) To increase the token count of the prompt.\nD) To change the agent''s assigned toolset.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'In the context of Multi-Agent Systems (MAS), what mechanism is typically used for a ''Planner Agent'' to decompose a high-level task into smaller, actionable sub-tasks for specialized agents?\nA) Simple keyword matching\nB) Hierarchical Task Networks (HTN) or recursive self-prompting.\nC) Manual hard-coding by the developer.\nD) Random selection of available APIs.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'When building an agentic workflow for a highly regulated industry like finance, which key design principle for the ''Act'' phase is most crucial for compliance and auditing?\nA) Prioritizing speed over accuracy.\nB) Ensuring all actions are fully idempotent and logged with attribution.\nC) Limiting the agent to only internal data.\nD) Avoiding the use of any external APIs.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'The term ''tool-use'' in Agentic AI refers to the LLM''s capability to:\nA) Access only the files it was originally trained on.\nB) Generate Python code only.\nC) Determine when and how to call external functions (APIs) to extend its capabilities beyond language generation.\nD) Manually modify its core model weights.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'A key challenge in scaling a Multi-Agent System (MAS) in an enterprise environment is dealing with potential ''conflicts'' or ''miscommunications.'' This is primarily mitigated through:\nA) Assigning all tasks to a single, monolithic agent.\nB) Implementing robust communication protocols and a central coordinator or arbitration mechanism.\nC) Doubling the size of the underlying LLM.\nD) Removing all external tool access.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'Which of the following best defines ''Task Decomposition'' in an agentic workflow?\nA) The agent forgetting its prior instructions.\nB) Breaking down a complex user goal into a sequence of smaller, manageable, and executable steps.\nC) Merging two different AI models into one.\nD) The process of training a smaller, less capable model.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'What advantage does using ''Dynamic Workers'' (as seen in modern cloud platforms) offer for scaling Agentic AI execution layers?\nA) Eliminating the need for GPUs.\nB) Providing faster, on-demand environments for executing AI-generated code without container overhead.\nC) Limiting agent access to only public data.\nD) Automatically writing unit tests for the agent.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'In a sophisticated RAG architecture, what is the role of the ''Re-ranking'' step after initial vector retrieval?\nA) To remove sensitive data from the retrieved documents.\nB) To sort the initially retrieved documents based on deeper semantic relevance to the query before passing them to the LLM.\nC) To change the embedding model used for the vectors.\nD) To generate new summary text for the documents.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'The concept of ''long-term memory'' for an AI agent is most commonly implemented using a:\nA) Simple text file storage system.\nB) Vector database (Vector Store) to store and retrieve contextual embeddings.\nC) Standard SQL relational database.\nD) Browser cookie storage.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'Why is ''Prompt Engineering'' considered fundamentally different and more complex for an AI Agent compared to a static LLM prompt?\nA) Agents ignore system prompts entirely.\nB) An agent''s prompt must include not just the initial query but also instructions for multi-step reasoning, tool selection, and reflection logic.\nC) Agents are only compatible with specific programming languages.\nD) An agent''s prompt must be less than 50 words.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'What is ''grounding'' in the context of an Agentic AI system operating in an enterprise environment?\nA) Connecting the agent to the internet.\nB) Ensuring the agent''s actions and responses are aligned with verifiable, internal enterprise data and policies.\nC) Limiting the agent''s processing power.\nD) Designing the user interface for the agent.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'The ''Observing'' phase of the Agent Loop often involves the agent analyzing which type of output from its external tools or systems?\nA) Only internal latency reports.\nB) Real-time API response status codes, error messages, and structured output data (JSON/XML).\nC) The agent''s current CPU utilization.\nD) The total number of users interacting with the system.', 'D');
