INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Agentic AI' LIMIT 1), 'bidding', 'medium', E'In the Agent-to-Agent (A2A) communication model, what is the primary role of the ''Artifact'' being passed between agents?\nA) To serve as a simple greeting message.\nB) To contain the structured data, partial results, or necessary context generated by one agent for the next agent to use.\nC) To delete all previous conversation history.\nD) To trigger a full model re-training.', 'D');
