INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'medium', E'What is a ''Man-in-the-Middle'' (MitM) attack?\nA) An attack where a hacker physically enters a building\nB) An attack where a hacker secretly intercepts and potentially alters communication between two parties\nC) A social engineering call to an employee\nD) A brute-force attack on a password', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'medium', E'What is ''public key infrastructure'' (PKI)?\nA) A public database of all known cyberattacks\nB) A framework of policies, hardware, and software used to manage digital certificates and public-key encryption\nC) A type of network firewall architecture\nD) A cloud security certification standard', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'medium', E'What is a ''honeypot'' in cybersecurity?\nA) A reward system for ethical hackers\nB) A decoy system designed to attract and detect attackers, allowing security teams to study their methods\nC) A type of encryption algorithm\nD) A secure storage vault for passwords', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'medium', E'What does ''GDPR'' stand for and what is its primary purpose?\nA) General Data Processing Rules — a firewall standard\nB) General Data Protection Regulation — a European law protecting individuals'' personal data and privacy\nC) Global Data Privacy Regulation — a US cybersecurity law\nD) General Digital Protection Rules — an international encryption standard', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'medium', E'What is ''credential stuffing''?\nA) Adding extra characters to a password\nB) An automated attack using stolen username/password pairs from one breach to try to access other accounts\nC) A brute-force attack that guesses random passwords\nD) A phishing technique targeting IT admins', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'medium', E'What is the role of a ''Certificate Authority'' (CA) in web security?\nA) It stores user passwords securely\nB) It is a trusted organization that issues digital certificates to verify the identity of websites and entities\nC) It monitors network traffic for intrusions\nD) It manages firewall rules for enterprises', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'A web application stores user passwords as plain MD5 hashes. Why is this considered insecure, and what is the recommended alternative?\nA) MD5 is too slow; use SHA-1 instead\nB) MD5 is fast and vulnerable to rainbow table attacks; use a slow, salted hashing algorithm like bcrypt or Argon2\nC) MD5 hashes are too long; use shorter hashes\nD) MD5 is insecure because it encrypts data instead of hashing it', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What is the difference between ''symmetric'' and ''asymmetric'' encryption?\nA) Symmetric encryption is stronger; asymmetric is weaker\nB) Symmetric uses the same key for encryption and decryption; asymmetric uses a public key to encrypt and a private key to decrypt\nC) Asymmetric uses the same key for both; symmetric uses two different keys\nD) Symmetric is used only for file storage; asymmetric is only for passwords', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What is ''lateral movement'' in the context of a cyberattack?\nA) Physically moving servers to a different location\nB) After gaining initial access, an attacker moves through a network to reach higher-value systems or data\nC) An attacker changing their IP address to avoid detection\nD) A firewall technique to redirect suspicious traffic', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What is ''OWASP'' and why is it relevant to developers?\nA) A government cybersecurity agency\nB) An open-source community that publishes widely-used security standards, including the OWASP Top 10 list of critical web application vulnerabilities\nC) A commercial antivirus product\nD) A cloud security certification program', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What distinguishes a ''vulnerability'' from an ''exploit'' in cybersecurity?\nA) They are the same term used interchangeably\nB) A vulnerability is a weakness in a system; an exploit is the tool or technique used to take advantage of that weakness\nC) An exploit is a theoretical risk; a vulnerability is an active attack\nD) A vulnerability is a software bug; an exploit is a hardware flaw', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What is ''DNS spoofing'' (or DNS cache poisoning)?\nA) A method to speed up DNS lookups\nB) An attack that corrupts a DNS resolver''s cache with false records, redirecting users to malicious websites without their knowledge\nC) A technique to block certain websites on a network\nD) A DDoS attack targeting DNS servers', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'In network security, what is the purpose of ''network segmentation''?\nA) Increasing network speed by dividing bandwidth\nB) Dividing a network into isolated zones so that a breach in one segment cannot easily spread to others\nC) Assigning different IP addresses to different departments\nD) Encrypting traffic between network switches', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What is ''security by obscurity'' and why is it generally considered insufficient on its own?\nA) A strong security strategy based on hiding system details\nB) Relying solely on keeping system details secret for security — insufficient because once details are discovered, no real security mechanism exists\nC) A type of two-factor authentication method\nD) An encryption standard for classified systems', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What is the difference between an ''IDS'' (Intrusion Detection System) and an ''IPS'' (Intrusion Prevention System)?\nA) They are the same system with different names\nB) An IDS monitors and alerts on suspicious activity; an IPS actively blocks or prevents detected threats in real time\nC) An IPS monitors traffic; an IDS blocks it\nD) An IDS is hardware-based; an IPS is always software-based', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'A company suffers a ransomware attack. What is the single most effective pre-existing safeguard that allows them to recover without paying the ransom?\nA) Having a strong password policy\nB) Maintaining secure, regularly tested, offline backups of critical data\nC) Using antivirus software\nD) Having a cybersecurity insurance policy', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What is ''typosquatting'' and how is it used as a cyberattack?\nA) A brute-force attack on login forms\nB) Registering domain names with common misspellings of popular websites to capture traffic from users who mistype the URL, often for phishing\nC) A method of injecting code into web forms\nD) A social engineering attack via phone', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What is a ''supply chain attack'' in cybersecurity?\nA) An attack targeting logistics and shipping companies only\nB) An attack that compromises a trusted third-party vendor or software component to gain access to the target organization through a trusted channel\nC) A DDoS attack on e-commerce platforms\nD) An attack targeting a company''s inventory database', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What does ''threat modeling'' involve in secure system design?\nA) Predicting future cyberattack trends using AI\nB) Systematically identifying potential threats, vulnerabilities, and attack vectors for a system during design — before it is built or deployed\nC) Testing a live system for real-time threats\nD) Training employees to recognize phishing emails', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What is ''token-based authentication'' and how does it improve security over traditional session cookies?\nA) Using a physical USB token for login\nB) Using a signed token (like JWT) that contains user claims and is verified without server-side session storage, reducing server load and improving scalability\nC) Replacing passwords with biometric data\nD) Storing authentication state in the browser''s local storage', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Cybersecurity' LIMIT 1), 'bidding', 'hard', E'What is the ''kill chain'' model in cybersecurity, and how is it used defensively?\nA) A sequence of physical security measures\nB) A framework that maps the stages of a cyberattack (from reconnaissance to exfiltration) so defenders can identify and disrupt an attack at any stage before it is completed\nC) A method of shutting down compromised servers\nD) A patch management workflow', 'B');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'What is the foundational technology that Bitcoin and other cryptocurrencies are built upon?\nA) Cloud Computing\nB) Blockchain\nC) Quantum Mechanics\nD) Centralized Databases', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'In a blockchain, what is a ''block''?\nA) A single digital coin.\nB) A container for verified transaction records.\nC) A hardware component in a mining rig.\nD) A type of software wallet.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'Which key characteristic of blockchain technology ensures that once data is recorded, it cannot be tampered with?\nA) Scalability\nB) Volatility\nC) Immutability\nD) Anonymity', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'What is the process called when computers solve complex math problems to validate transactions and add new blocks to a Proof-of-Work chain?\nA) Staking\nB) Coding\nC) Mining\nD) Hacking', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'What mechanism do decentralized networks use to agree on the single, true state of the ledger?\nA) CEO Mandate\nB) Consensus Mechanism\nC) Government Regulation\nD) Server Restart', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'Who is widely credited with the creation of Bitcoin, the first major blockchain application?\nA) Elon Musk\nB) Vitalik Buterin\nC) Satoshi Nakamoto\nD) Jeff Bezos', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'What is a "Smart Contract"?\nA) A paper contract signed digitally.\nB) Self-executing code that automatically executes terms and conditions.\nC) An AI that negotiates salaries for employees.\nD) A contract that can only be read by computers.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'Which term refers to the unique identifier used to receive funds on a blockchain, often shared publicly?\nA) Private Key\nB) Public Address\nC) Password\nD) Wallet Seed', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'What is a ''node'' in a blockchain network?\nA) A physical server located at the network creator''s office.\nB) A computer running the blockchain software and validating transactions.\nC) A single transaction''s data payload.\nD) An error log file.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'Which type of blockchain is open to the public, allowing anyone to join, view transactions, and participate in validation?\nA) Private Blockchain\nB) Consortium Blockchain\nC) Permissioned Blockchain\nD) Public Blockchain', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'What provides the cryptographic link between one block and the next in the chain?\nA) A time-stamp\nB) The previous block''s hash\nC) The miner''s name\nD) A transaction ID', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'What is the fundamental difference between a ''fungible'' token (like Bitcoin) and a ''Non-Fungible Token'' (NFT)?\nA) Fungible tokens are always cheaper.\nB) NFTs are unique and non-interchangeable; fungible tokens are interchangeable.\nC) Fungible tokens can be traded, but NFTs cannot.\nD) NFTs are stored offline; fungible tokens are stored online.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'Which consensus mechanism relies on participants ''locking up'' their crypto assets to gain the right to validate transactions?\nA) Proof of Work (PoW)\nB) Proof of Space (PoS)\nC) Proof of Stake (PoS)\nD) Proof of Authority (PoA)', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'How does blockchain improve transparency in a supply chain context?\nA) By making all logistics companies share their financial data.\nB) By creating an unchangeable, auditable trail of a product''s origin and movement.\nC) By using faster shipping methods.\nD) By replacing all physical paperwork with email.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'What is the primary function of a ''hashing algorithm'' (like SHA-256) in blockchain?\nA) To compress files into a smaller size.\nB) To convert data of any size into a unique, fixed-length string.\nC) To increase the network''s transaction speed.\nD) To execute smart contract code.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'Which use case leverages blockchain to ensure that a voting record cannot be altered?\nA) Central Bank Digital Currency (CBDC)\nB) Decentralized Voting Systems\nC) Cloud Storage Backups\nD) Video Conferencing', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'What is a ''transaction fee'' or ''gas fee'' used for on a blockchain like Ethereum?\nA) To pay for the cost of the user''s internet service.\nB) To compensate validators (miners/stakers) for processing the transaction.\nC) To purchase a new crypto asset.\nD) A tax paid to a centralized authority.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'A ''Private Key'' is essential because it allows the user to:\nA) Access the internet privately.\nB) Receive assets into their wallet.\nC) Prove ownership and authorize the movement of funds.\nD) View the entire transaction history of the network.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'What term describes a potential vulnerability where one entity controls more than half of the network''s computing power (hash rate)?\nA) Fork Attack\nB) Sybil Attack\nC) 51% Attack\nD) DDoS Attack', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'rapid_fire', 'easy', E'In enterprise adoption, a consortium (or permissioned) blockchain is typically controlled by:\nA) The general public.\nB) A small, pre-selected group of organizations.\nC) A single software vendor.\nD) Anonymous individuals.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'What is the primary function of a Layer-2 scaling solution, such as the Lightning Network on Bitcoin or Polygon on Ethereum?\nA) To replace the underlying Layer-1 chain entirely.\nB) To process a large volume of transactions off-chain before settling the final result on the main chain, improving speed and reducing fees.\nC) To change the network''s consensus mechanism from Proof-of-Work to Proof-of-Stake.\nD) To allow anonymous transactions by obscuring sender and receiver addresses.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'In a public-key cryptography system used in blockchain, what is the private key specifically used for, besides authorizing a transaction?\nA) Calculating the public address to receive funds.\nB) Generating the digital signature that proves ownership of the transaction''s input funds.\nC) Encrypting the entire blockchain ledger for security.\nD) Retrieving the previous block''s hash.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'Which consensus mechanism introduces a layer of elected delegates or validators to vote on block validation, often resulting in faster transaction speeds compared to pure Proof-of-Stake?\nA) Proof of Work (PoW)\nB) Delegated Proof of Stake (DPoS)\nC) Proof of Authority (PoA)\nD) Byzantine Fault Tolerance (BFT)', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'In blockchain development, what defines a ''Hard Fork''?\nA) A mandatory software update that is backward-compatible with the old rules.\nB) A protocol upgrade that is not backward-compatible, permanently splitting the chain into two separate networks if nodes do not unanimously upgrade.\nC) A temporary network congestion issue due to high transaction volume.\nD) A minor software patch that fixes a security bug.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'For a smart contract designed to execute a payout based on real-world events (e.g., a sports outcome or stock price), what component is critical for securely bridging this external data to the decentralized environment?\nA) A centralized exchange\nB) A Block Explorer\nC) An Oracle Network\nD) A Multi-signature Wallet', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'What is the primary concern addressed by the ''Blockchain Trilemma'' concept?\nA) The challenge of balancing security, profitability, and accessibility.\nB) The difficulty of achieving decentralization, security, and scalability simultaneously without compromise.\nC) The competition between three major cryptocurrencies.\nD) The regulatory challenges faced by decentralized applications (DApps).', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'Which data structure does a Merkle Tree (or hash tree) utilize to efficiently and securely verify the contents of a large data set, often used to summarize all transactions in a block?\nA) A linear linked list\nB) A single, non-indexed array\nC) A cryptographic tree of hashes\nD) A standard relational database table', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'What is ''Immutability'' in the context of blockchain, and why is it a core security feature?\nA) The ability for the network to process transactions quickly.\nB) The guarantee that once a block is added and confirmed, its data cannot be retrospectively altered or deleted without invalidating the entire subsequent chain.\nC) The volatility of the asset’s price over time.\nD) The ability for the code to be open-source.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'In the Ethereum ecosystem, what does ''Gas'' fundamentally represent?\nA) The maximum number of transactions a block can hold.\nB) A unit measuring the computational effort required to execute a transaction or smart contract function.\nC) The total supply of ETH in circulation.\nD) A reward distributed to every user who holds ETH.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'What is a Decentralized Autonomous Organization (DAO)?\nA) A company governed by a traditional board of directors and shareholders.\nB) An organization represented by rules encoded as a transparent computer program, controlled by token holders, and not influenced by a central government.\nC) A secure, off-chain data storage solution.\nD) A non-profit foundation that builds blockchain software.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'What security measure ensures that a newly created block is computationally expensive to create, deterring malicious actors from performing a 51% attack on a Proof-of-Work chain?\nA) A mandatory waiting period set by a central authority.\nB) The inclusion of a random ''nonce'' value that must be brute-forced until the block''s hash meets a specified target difficulty.\nC) Encrypting the transactions using a quantum-resistant algorithm.\nD) Requiring a two-thirds majority vote from all network users.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'What is the primary distinction between a ''permissioned'' (private/consortium) blockchain and a ''permissionless'' (public) blockchain in a business context?\nA) Permissioned chains do not use cryptography.\nB) Permissionless chains have faster transaction speeds.\nC) Permissioned chains restrict who can participate, validate transactions, and view the ledger, whereas permissionless chains are open to all.\nD) Permissioned chains are immune to 51% attacks.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'What critical function does an Elliptic Curve Digital Signature Algorithm (ECDSA) provide in a typical blockchain transaction?\nA) It optimizes the transaction routing across the network.\nB) It allows the receiver to decrypt the transaction data.\nC) It mathematically verifies that the transaction was initiated and authorized by the holder of the private key.\nD) It compresses the size of the block data.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'When a user runs a ''Light Node'' (or SPV client), what information does it rely on to verify the validity of a transaction without downloading the entire blockchain history?\nA) A manual confirmation from a trusted authority.\nB) The block headers and the cryptographic proof (Merkle proof) linking the transaction to the block.\nC) The node''s internal cache of recent transactions.\nD) The total market capitalization of the cryptocurrency.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'medium', E'What does the field of ''Cryptoeconomics'' primarily study in relation to blockchain networks?\nA) The history of digital currency regulation.\nB) The design of economic incentives and penalties (rewards and punishments) that ensure rational, self-interested participants act in the network''s best interest.\nC) The cost analysis of hardware for mining.\nD) The prediction of future crypto asset prices.', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'hard', E'Which cryptographic primitive ensures that only the sender of a transaction could have produced the signature, preventing a "double-spend" attack?\nA) Symmetric Encryption\nB) Merkle Root Verification\nC) Elliptic Curve Digital Signature Algorithm (ECDSA)\nD) Zero-Knowledge Proof (ZKP)', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'hard', E'What is the term for a transaction that utilizes both the private keys of a wallet and an external condition (like a time-lock or data from an Oracle) to execute?\nA) Single-Sig Transaction\nB) Atomic Swap\nC) Multi-Signature (Multi-Sig) or Conditional Transaction\nD) Segregated Witness (SegWit)', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'hard', E'What mechanism is used in Proof-of-Work systems like Bitcoin to adjust the difficulty of mining so that the average time between blocks remains constant, typically around 10 minutes?\nA) Halving Event\nB) Difficulty Adjustment Algorithm (DAA)\nC) Consensus Fork\nD) Gas Limit Control', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'hard', E'In the context of a Distributed Ledger Technology (DLT) like Hyperledger Fabric, what term refers to the logic that defines how transactions are verified and endorsed by a subset of the network participants before being committed to the ledger?\nA) Chaincode (Smart Contract)\nB) Ordering Service\nC) Endorsement Policy\nD) Peer-to-Peer Protocol', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'hard', E'A ''State Channel'' (like the Lightning Network or Raiden) is a Layer-2 scaling solution that addresses which major limitation of Layer-1 blockchains?\nA) Network Decentralization\nB) High Transaction Latency and Cost (Scalability)\nC) Code Immutability\nD) Private Key Security', 'D');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'hard', E'What is the core innovation of a ''Directed Acyclic Graph'' (DAG) based DLT, such as IOTA or Fantom, compared to a linear blockchain structure?\nA) It eliminates the need for any form of cryptography.\nB) It allows parallel processing of transactions, potentially enabling infinite scalability and eliminating blocks.\nC) It requires a single central authority to validate all transactions.\nD) It only stores non-fungible tokens (NFTs).', 'D');
