INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Blockchain' LIMIT 1), 'bidding', 'hard', E'What is ''Sharding'' as a primary solution for blockchain scalability?\nA) Storing transaction data in off-chain databases.\nB) Splitting the blockchain''s state and history into multiple smaller, manageable segments (shards) that can process transactions in parallel.\nC) Using zero-knowledge proofs to hide transaction details.\nD) Replacing the consensus mechanism with a centralized one.', 'D');
