INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'What is the significance of the threshold theorem in quantum error correction?\nA) If the physical error rate is below a certain threshold, arbitrary long quantum computations are possible with error correction\nB) Quantum computers will never be fault-tolerant\nC) Error correction is impossible\nD) Only classical errors can be corrected', 'A');
