INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'What does “blind quantum computing” refer to?\nA) A client can perform quantum computation on a remote server without revealing the computation to the server\nB) Computing without any qubits\nC) Classical simulation of quantum circuits\nD) Quantum computers that cannot be programmed', 'A');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'In variational quantum algorithms (like VQE), what is the hybrid quantum-classical approach used for?\nA) Finding ground states of molecules using parameterized circuits optimized classically\nB) Factoring large numbers faster\nC) Replacing all classical optimization\nD) Purely quantum simulation without classical feedback', 'A');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'What is the main bottleneck in photonic quantum computing for universal computation?\nA) Efficient generation of large-scale entanglement and deterministic two-qubit gates\nB) High decoherence\nC) Room-temperature operation\nD) Lack of single-photon sources', 'A');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'Which metric combines qubit count, connectivity, and gate fidelity to benchmark quantum processors?\nA) Quantum Volume\nB) Qubit count only\nC) Gate speed only\nD) Classical FLOPS', 'A');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'What is the key idea behind quantum error mitigation techniques (used in NISQ devices)?\nA) Reducing the effect of noise statistically without full error correction\nB) Adding more physical qubits\nC) Using only classical post-processing\nD) Ignoring errors completely', 'A');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'In quantum machine learning, what is the HHL algorithm designed to solve?\nA) Linear systems of equations exponentially faster (under certain conditions)\nB) Image classification\nC) Clustering\nD) Reinforcement learning', 'A');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'What is the Gottesman-Knill theorem about?\nA) Certain quantum circuits (Clifford circuits) can be efficiently simulated classically\nB) All quantum circuits are easy to simulate\nC) Quantum supremacy is impossible\nD) Error correction is always required', 'A');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'Which quantum computing architecture is being pursued by Microsoft for its topological qubits?\nA) Majorana zero modes\nB) Superconducting transmons\nC) Trapped ions\nD) Photonic qubits', 'A');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'What is the primary reason quantum computers are not expected to replace classical computers entirely?\nA) Quantum computers excel only at specific tasks; classical computers are better for most everyday computations\nB) Quantum computers are slower for all tasks\nC) Quantum computers cannot run algorithms\nD) They use too little power', 'A');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'In the context of quantum simulation, what does “digital quantum simulation” use?\nA) Trotterization and gate-based circuits to approximate time evolution\nB) Analog Hamiltonian simulation only\nC) Classical Monte Carlo methods\nD) No qubits at all', 'A');
INSERT INTO public.questions (domain_id, round_type, difficulty, content, correct_answer) VALUES ((SELECT id FROM public.domains WHERE name = 'Quantum Computing' LIMIT 1), 'rapid_fire', 'easy', E'What is the current theoretical limit discussed for quantum advantage in practical applications?\nA) Achieving useful quantum advantage requires both error-corrected logical qubits and algorithms that outperform classical methods in real-world problems\nB) Quantum advantage is already achieved for all problems\nC) Only 10 logical qubits are sufficient forever\nD) Classical computers will always be superior in every domain', 'A');
